export interface MemoryProvider {
  provider: "maple_managed" | "external";
  search(request: {
    workspaceId: string;
    storeId: string;
    query: string;
    filters?: Record<string, unknown>;
    limit?: number;
  }): Promise<MemorySearchResult[]>;
  write(request: {
    workspaceId: string;
    storeId: string;
    key: string;
    value: string;
    scope: "project" | "session" | "user" | "workspace";
    metadata?: Record<string, unknown>;
  }): Promise<{ id: string }>;
  delete?(request: { workspaceId: string; storeId: string; id: string }): Promise<void>;
  export?(request: { workspaceId: string; storeId: string; scope?: string }): AsyncIterable<unknown>;
}

export interface McpAuthTransform {
  type: string;
  prepare(input: {
    workspaceId: string;
    userHeaders: Record<string, string>;
    vault: VaultReader;
    mcp: McpRegistryEntry;
    phase: "initialize" | "tools_list" | "tools_call";
  }): Promise<Record<string, string>>;
}
